  }
}

function sanitizeGitIdentityName(rawName) {
  const value = String(rawName || '')
    .replace(/[\r\n\t]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!value) return '';
  return value.length > 80 ? value.slice(0, 80).trim() : value;
}

function buildGitIdentityFromUsername(rawUsername) {
